#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#define MAX 100
#define MAXL 100
char **strs;
int n;
void sort_str(char *str) {
    int len = strlen(str);
    for (int i = 0; i < len - 1; i++) {
        for (int j = i + 1; j < len; j++) {
            if (str[i] > str[j]) {
                char temp = str[i];
                str[i] = str[j];
                str[j] = temp;
            }
        }
    }
}
int is_subsequence(char *str1, char *str2) {
    int len1 = strlen(str1);
    int len2 = strlen(str2);
    int i = 0;
    int j = 0;
    while (i < len1 && j < len2) {
        if (str1[i] == str2[j]) {
            i++;
        }
        j++;
    }
    return i == len1;
}
int main() {
    scanf("%d", &n);
    strs = (char **)malloc(n * sizeof(char *));
    for (int i = 0; i < n; i++) {
        strs[i] = (char *)malloc((MAXL + 1) * sizeof(char));
        scanf("%s", strs[i]);
    }
    char *longest = (char *)malloc((MAXL + 1) * sizeof(char));
    longest[0] = '\0';
    for (int len = 1; len <= MAXL; len++) {
        for (int i = 0; i < n; i++) {
            for (int j = 0; j <= strlen(strs[i]) - len; j++) {
                char *substr = (char *)malloc((len + 1) * sizeof(char));
                strncpy(substr, strs[i] + j, len);
                substr[len] = '\0';
                sort_str(substr);
                int is_sub = 1;
                for (int k = 0; k < n; k++) {
                    if (!is_subsequence(substr, strs[k])) {
                        is_sub = 0;
                        break;
                    }
                }
                if (is_sub && strlen(substr) > strlen(longest)) {
                    strcpy(longest, substr);
                }
                free(substr);
            }
        }
    }
    if (strlen(longest) == 0) {
        printf("no such string\n");
    } else {
        printf("%s\n", longest);
    }
    for (int i = 0; i < n; i++) {
        free(strs[i]);
    }
    free(strs);
    free(longest);
    return 0;
}

