#define MAXL 100
string strs[MAX];
int n;
bool is_subsequence(string str1, string str2) {
    int len1 = str1.length();
    int len2 = str2.length();
    int i = 0;
    int j = 0;
    while (i < len1 && j < len2) {
        if (str1[i] == str2[j]) {
            i++;
        }
