    ios::sync_with_stdio(false);
    cin.tie(NULL);
    cin >> n;
    for (int i = 0; i < n; i++) {
        cin >> strs[i];
    }
    string longest = "";
    for (int len = 1; len <= MAXL; len++) {
        for (int i = 0; i < n; i++) {
            for (int j = 0; j <= strs[i].length() - len; j++) {
